import{_ as e,o as t,c as i,a2 as n}from"./chunks/framework.Crpw6aS5.js";const u=JSON.parse('{"title":"主题索引","description":"","frontmatter":{},"headers":[],"relativePath":"02_concepts/index.md","filePath":"02_concepts/index.md"}'),l={name:"02_concepts/index.md"};function o(r,a,c,h,s,p){return t(),i("div",null,[...a[0]||(a[0]=[n('<h1 id="主题索引" tabindex="-1">主题索引 <a class="header-anchor" href="#主题索引" aria-label="Permalink to &quot;主题索引&quot;">​</a></h1><p>按主题分类阅读巴菲特致股东信的核心思想，提炼70年投资智慧的精华。</p><hr><h2 id="投资哲学" tabindex="-1">投资哲学 <a class="header-anchor" href="#投资哲学" aria-label="Permalink to &quot;投资哲学&quot;">​</a></h2><ul><li><a href="/02_concepts/intrinsic-value.html">内在价值 Intrinsic Value</a> — 企业真正值多少钱，是所有投资决策的基石</li><li><a href="/02_concepts/moat.html">护城河 Moat</a> — 竞争优势的宽度与持久度</li><li><a href="/02_concepts/safety-margin.html">安全边际 Margin of Safety</a> — 用折扣价格买好资产，永远不为估值付出太多</li><li><a href="/02_concepts/compounding.html">复利 Compounding</a> — 世界第八大奇迹，时间是伟大事业的朋友</li></ul><h2 id="业务分析" tabindex="-1">业务分析 <a class="header-anchor" href="#业务分析" aria-label="Permalink to &quot;业务分析&quot;">​</a></h2><ul><li><a href="/02_concepts/insurance-float.html">保险浮存金 Insurance Float</a> — 伯克希尔的秘密引擎：低成本甚至负成本的浮存金</li><li><a href="/02_concepts/underwriting-discipline.html">承保纪律 Underwriting Discipline</a> — 不做价格战，守住利润底线</li><li><a href="/02_concepts/capital-allocation.html">资本配置 Capital Allocation</a> — 把每一分钱用在刀刃上</li></ul><h2 id="思维方法" tabindex="-1">思维方法 <a class="header-anchor" href="#思维方法" aria-label="Permalink to &quot;思维方法&quot;">​</a></h2><ul><li><a href="/02_concepts/circle-of-competence.html">能力圈 Circle of Competence</a> — 知道自己知道什么，比知道什么更重要</li><li><a href="/02_concepts/contrarian.html">逆向思维 Contrarian Thinking</a> — 别人贪婪时恐惧，别人恐惧时贪婪</li><li><a href="/02_concepts/risk.html">风险与回报 Risk &amp; Return</a> — 真正的风险是永久损失，而非短期波动</li></ul><h2 id="人生智慧" tabindex="-1">人生智慧 <a class="header-anchor" href="#人生智慧" aria-label="Permalink to &quot;人生智慧&quot;">​</a></h2><ul><li><a href="/02_concepts/reputation.html">声誉 Reputation</a> — 建立声誉需要20年，毁掉它只需5分钟</li><li><a href="/02_concepts/management.html">管理层选择 Management</a> — 找到对的船长，即使船在漏水</li><li><a href="/02_concepts/long-term.html">长期主义 Long-term Thinking</a> — 如果你不愿意持有一只股票十年，那就不要持有它十分钟</li></ul><hr><blockquote><p>💡 <strong>使用建议</strong>：每个主题页面都来自70年股东信的原文提炼，配有巴菲特的原话和对应年份。建议从&quot;投资哲学&quot;开始，再按个人兴趣深入各子主题。</p></blockquote>',13)])])}const _=e(l,[["render",o]]);export{u as __pageData,_ as default};
